import React, { useState } from 'react';
import { Box, Typography, InputBase, IconButton, Chip, Grid, Button, Stack, Select, MenuItem, FormControl, InputLabel, Divider } from '@mui/material';
import { Search, FilterList, DirectionsCar } from '@mui/icons-material';
import { styled, alpha, useTheme } from '@mui/material/styles';
import { motion } from 'framer-motion';
import CarCard from '../components/cards/CarCard';

const SearchContainer = styled(Box)(({ theme }) => ({
  position: 'relative',
  borderRadius: 100,
  backgroundColor: alpha(theme.palette.common.white, 1),
  boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
  width: '100%',
  marginBottom: theme.spacing(3),
  marginTop: theme.spacing(2),
  [theme.breakpoints.up('sm')]: {
    marginLeft: 0,
  },
}));

const SearchIconWrapper = styled('div')(({ theme }) => ({
  padding: theme.spacing(0, 2),
  height: '100%',
  position: 'absolute',
  pointerEvents: 'none',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: alpha(theme.palette.text.secondary, 0.7),
}));

const StyledInputBase = styled(InputBase)(({ theme }) => ({
  width: '100%',
  '& .MuiInputBase-input': {
    padding: theme.spacing(1.5, 1.5, 1.5, 0),
    paddingLeft: `calc(1em + ${theme.spacing(4)})`,
    transition: theme.transitions.create('width'),
    width: '100%',
  },
}));

const FilterChip = styled(Chip)(({ theme }) => ({
  margin: theme.spacing(0, 0.5, 1, 0),
  backgroundColor: alpha(theme.palette.primary.main, 0.1),
  color: theme.palette.primary.main,
  fontWeight: 500,
  '&.MuiChip-clickable:hover': {
    backgroundColor: alpha(theme.palette.primary.main, 0.2),
  },
  '&.MuiChip-clickable:active': {
    backgroundColor: alpha(theme.palette.primary.main, 0.3),
  },
}));

const FilterButton = styled(Button)(({ theme }) => ({
  borderRadius: 100,
  textTransform: 'none',
  padding: theme.spacing(1, 2),
  fontWeight: 600,
  boxShadow: 'none',
}));

const AnimatedBox = styled(motion.div)({
  width: '100%',
});

const BannerContainer = styled(Box)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  overflow: 'hidden',
  position: 'relative',
  height: 240,
  marginBottom: theme.spacing(4),
  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  color: 'white',
  boxShadow: '0 10px 30px rgba(0,0,0,0.15)',
  display: 'flex',
  alignItems: 'center',
  padding: theme.spacing(3, 4),
  [theme.breakpoints.down('sm')]: {
    padding: theme.spacing(2),
    height: 'auto',
    flexDirection: 'column',
    textAlign: 'center',
  },
}));

const BannerContent = styled(Box)(({ theme }) => ({
  zIndex: 1,
  maxWidth: '60%',
  [theme.breakpoints.down('sm')]: {
    maxWidth: '100%',
  },
}));

const BannerImage = styled(Box)(({ theme }) => ({
  position: 'absolute',
  right: theme.spacing(4),
  top: 0,
  height: '100%',
  width: '40%',
  backgroundImage: `url('https://images.unsplash.com/photo-1494976388531-d1058494cdd8?q=80&w=1000&auto=format&fit=crop')`,
  backgroundSize: 'cover',
  backgroundPosition: 'center',
  [theme.breakpoints.down('sm')]: {
    display: 'none',
  },
}));

// Данные о розыгрышах
const carData = [
  {
    id: '1',
    title: 'BMW X5',
    image: 'https://images.unsplash.com/photo-1617469767053-3f7c8cff7a6d?q=80&w=1000&auto=format&fit=crop',
    description: 'Роскошный внедорожник премиум-класса с мощным двигателем и комфортным салоном',
    ticketsSold: 456,
    totalTickets: 1000,
    price: 1000,
    year: 2022,
    participants: 400,
    endDate: '15.12.2023'
  },
  {
    id: '2',
    title: 'Mercedes-Benz S-Class',
    image: 'https://images.unsplash.com/photo-1618843479313-40f8afb4b4d8?q=80&w=1000&auto=format&fit=crop',
    description: 'Флагманский седан с передовыми технологиями и непревзойденным комфортом',
    ticketsSold: 789,
    totalTickets: 1500,
    price: 1500,
    year: 2023,
    participants: 700,
    endDate: '20.01.2024'
  },
  {
    id: '3',
    title: 'Audi Q7',
    image: 'https://images.unsplash.com/photo-1612825173281-9a193378527e?q=80&w=1000&auto=format&fit=crop',
    description: 'Полноразмерный кроссовер с просторным салоном и современными технологиями',
    ticketsSold: 350,
    totalTickets: 1200,
    price: 1200,
    year: 2023,
    participants: 320,
    endDate: '05.02.2024'
  },
  {
    id: '4',
    title: 'Tesla Model 3',
    image: 'https://images.unsplash.com/photo-1560958089-b8a1929cea89?q=80&w=1000&auto=format&fit=crop',
    description: 'Электрический седан с запасом хода до 500 км и инновационным автопилотом',
    ticketsSold: 890,
    totalTickets: 2000,
    price: 800,
    year: 2023,
    participants: 800,
    endDate: '10.12.2023'
  },
];

const HomePage: React.FC = () => {
  const theme = useTheme();
  const [search, setSearch] = useState('');
  const [sort, setSort] = useState('newest');
  const [filterDialogOpen, setFilterDialogOpen] = useState(false);
  
  // Анимации для элементов
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: { 
      opacity: 1,
      transition: { 
        staggerChildren: 0.1
      }
    }
  };
  
  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: { duration: 0.4 }
    }
  };
  
  return (
    <Box sx={{ padding: 2, paddingBottom: 10 }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6 }}
      >
        <BannerContainer>
          <BannerContent>
            <Typography variant="h4" component="h1" sx={{ fontWeight: 700, mb: 1 }}>
              Выиграй автомобиль мечты
            </Typography>
            <Typography variant="body1" sx={{ mb: 3, opacity: 0.9 }}>
              Участвуй в розыгрышах роскошных автомобилей. Купи билет и стань ближе к своей мечте!
            </Typography>
            <Button
              variant="contained"
              size="large"
              startIcon={<DirectionsCar />}
              sx={{
                backgroundColor: 'white',
                color: 'primary.main',
                borderRadius: 2,
                fontSize: '1rem',
                fontWeight: 600,
                padding: theme.spacing(1, 3),
                '&:hover': {
                  backgroundColor: alpha(theme.palette.common.white, 0.9),
                }
              }}
            >
              Текущие розыгрыши
            </Button>
          </BannerContent>
          <BannerImage />
        </BannerContainer>

        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
          <Typography variant="h5" component="h2" sx={{ fontWeight: 700 }}>
            Актуальные розыгрыши
          </Typography>
          
          <Box sx={{ display: 'flex', alignItems: 'center' }}>
            <FormControl variant="outlined" size="small" sx={{ minWidth: 120, mr: 1 }}>
              <Select
                value={sort}
                onChange={(e) => setSort(e.target.value as string)}
                displayEmpty
                sx={{ 
                  borderRadius: 2,
                  backgroundColor: 'white',
                  fontSize: '0.875rem',
                  '& .MuiOutlinedInput-notchedOutline': {
                    borderColor: alpha(theme.palette.divider, 0.5),
                  },
                }}
              >
                <MenuItem value="newest">Новые</MenuItem>
                <MenuItem value="ending">Заканчиваются</MenuItem>
                <MenuItem value="popular">Популярные</MenuItem>
                <MenuItem value="price_low">Цена: по возрастанию</MenuItem>
                <MenuItem value="price_high">Цена: по убыванию</MenuItem>
              </Select>
            </FormControl>
            
            <IconButton 
              aria-label="filter" 
              sx={{ 
                backgroundColor: alpha(theme.palette.primary.main, 0.1),
                color: theme.palette.primary.main,
                '&:hover': {
                  backgroundColor: alpha(theme.palette.primary.main, 0.2),
                }
              }}
              onClick={() => setFilterDialogOpen(!filterDialogOpen)}
            >
              <FilterList />
            </IconButton>
          </Box>
        </Box>
        
        <SearchContainer>
          <SearchIconWrapper>
            <Search />
          </SearchIconWrapper>
          <StyledInputBase
            placeholder="Поиск автомобилей..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </SearchContainer>
        
        {filterDialogOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.3 }}
          >
            <Box sx={{ mb: 3, p: 2, backgroundColor: alpha(theme.palette.background.paper, 0.5), borderRadius: 2 }}>
              <Typography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
                Фильтры
              </Typography>
              <Stack direction="row" spacing={1} sx={{ mb: 2, flexWrap: 'wrap' }}>
                <Typography variant="body2" sx={{ color: 'text.secondary', mr: 1, display: 'flex', alignItems: 'center' }}>
                  Марка:
                </Typography>
                <FilterChip label="BMW" clickable />
                <FilterChip label="Mercedes" clickable />
                <FilterChip label="Audi" clickable />
                <FilterChip label="Tesla" clickable />
                <FilterChip label="Porsche" clickable />
              </Stack>
              
              <Divider sx={{ my: 1 }} />
              
              <Stack direction="row" spacing={1} sx={{ mb: 1, flexWrap: 'wrap' }}>
                <Typography variant="body2" sx={{ color: 'text.secondary', mr: 1, display: 'flex', alignItems: 'center' }}>
                  Цена билета:
                </Typography>
                <FilterChip label="До 1000 ₽" clickable />
                <FilterChip label="1000-2000 ₽" clickable />
                <FilterChip label="Более 2000 ₽" clickable />
              </Stack>
              
              <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 2 }}>
                <Button size="small" sx={{ mr: 1 }}>
                  Сбросить все
                </Button>
                <Button variant="contained" size="small">
                  Применить
                </Button>
              </Box>
            </Box>
          </motion.div>
        )}
        
        <motion.div
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          <Grid container spacing={3}>
            {carData.map((car) => (
              <Grid size={{ xs: 12, sm: 6, md: 6, lg: 4 }} key={car.id}>
                <motion.div variants={itemVariants}>
                  <CarCard
                    id={car.id}
                    title={car.title}
                    image={car.image}
                    description={car.description}
                    ticketsSold={car.ticketsSold}
                    totalTickets={car.totalTickets}
                    price={car.price}
                    year={car.year}
                    participants={car.participants}
                    endDate={car.endDate}
                  />
                </motion.div>
              </Grid>
            ))}
          </Grid>
          
          <Box sx={{ display: 'flex', justifyContent: 'center', mt: 4 }}>
            <Button 
              variant="outlined" 
              color="primary"
              size="large"
              sx={{ 
                borderRadius: 100, 
                textTransform: 'none', 
                px: 4,
                boxShadow: '0 4px 12px rgba(33, 150, 243, 0.2)',
                '&:hover': {
                  boxShadow: '0 6px 16px rgba(33, 150, 243, 0.3)',
                }
              }}
            >
              Показать больше розыгрышей
            </Button>
          </Box>
        </motion.div>
      </motion.div>
    </Box>
  );
};

export default HomePage;
